
const SLIDES = [
  { src: "data:image/jpeg;base64,", caption: "Private tutoring sessions in action" },
  { src: "data:image/jpeg;base64,", caption: "Our main learning space" },
  { src: "data:image/jpeg;base64,", caption: "Learners focused during a session" },
  { src: "data:image/jpeg;base64,", caption: "Exam prep — full house" },
  { src: "data:image/jpeg;base64,", caption: "Our dedicated study environment" },
  { src: "data:image/jpeg;base64,", caption: "Blue Wizard Park — find us here" },
  { src: "data:image/jpeg;base64,", caption: "The MathsStudios team" },
];
let cgCur = 0, cgTimer;
const cgTrack = document.getElementById('cgtrack');
const cgCap   = document.getElementById('cgcap');
const cgDots  = document.getElementById('cgdots');

function cgBuild() {
  SLIDES.forEach((s, i) => {
    const img = document.createElement('img');
    img.src = s.src; img.alt = s.caption;
    cgTrack.appendChild(img);
    const d = document.createElement('button');
    d.className = 'cg-dot'; d.onclick = () => cgGoTo(i);
    cgDots.appendChild(d);
  });
  cgGoTo(0);
}

function cgGoTo(n) {
  cgCur = (n + SLIDES.length) % SLIDES.length;
  cgTrack.style.transform = `translateX(-${cgCur * 100}%)`;
  cgCap.style.opacity = 0;
  setTimeout(() => { cgCap.textContent = SLIDES[cgCur].caption; cgCap.style.opacity = 1; }, 250);
  cgDots.querySelectorAll('.cg-dot').forEach((d, i) => d.classList.toggle('active', i === cgCur));
  clearInterval(cgTimer);
  cgTimer = setInterval(() => cgGoTo(cgCur + 1), 4800);
}

function cgMove(dir) { cgGoTo(cgCur + dir); }
cgBuild();
